import{_ as e,c as s}from"./app.c70f1779.js";const a={},n=s(`<h1 id="tinywebserver\u624B\u64B8\u8BB0\u5F55" tabindex="-1"><a class="header-anchor" href="#tinywebserver\u624B\u64B8\u8BB0\u5F55" aria-hidden="true">#</a> TinyWebServer\u624B\u64B8\u8BB0\u5F55</h1><h2 id="\u524D\u8A00" tabindex="-1"><a class="header-anchor" href="#\u524D\u8A00" aria-hidden="true">#</a> \u524D\u8A00</h2><p>\u4F9D\u7A00\u8BB0\u5F97\u4E0A\u6B210\u57FA\u7840\u624B\u64B8\u9879\u76EE\u662F\u57283\u5E74\u524D\uFF0C\u5F53\u65F6\u57280\u57FA\u7840\u624B\u64B8vue\uFF0C\u4E00\u4E2A\u89C6\u9891\u6559\u7A0B\u6CA1\u770B\u7684\u60C5\u51B5\u4E0B\uFF0C\u4E00\u53E3\u6C14\u5199\u51FA\u4E86\u4E00\u4E2A\u51E0\u4E07\u884C\u7684\u524D\u540E\u7AEF\u9879\u76EE\uFF0C\u5E76\u4E14\u5B9E\u73B0\u4E86\u51E0\u4E2AW\u7684\u76C8\u5229\uFF0C\u5C3D\u7BA1\u73B0\u5728\u56DE\u60F3\u8D77\u6765\u90A3\u65F6\u5019\u4EE3\u7801\u8D28\u91CF\u4E0D\u9AD8\u3002</p><p>\u524D\u4E0D\u4E45\u5728\u624B\u64B8c++\u7684webserver\uFF0C\u5148\u540E\u770B\u4E86\u725B\u5BA2\u7684Linux\u670D\u52A1\u5668\u7F16\u7A0B\u7684\u89C6\u9891\uFF0C\u4EE5\u53CA\u300ATCP/IP\u7F51\u7EDC\u7F16\u7A0B\u300B\u3001\u300ALinux\u9AD8\u6027\u80FD\u670D\u52A1\u5668\u7F16\u7A0B\u300B\u8FD9\u4E24\u672C\u4E66\uFF0C\u52A0\u4E0A\u5148\u524D\u5728\u6613\u9053\u4E91\u7684\u7F51\u7EDC\u7F16\u7A0B\u57FA\u7840\uFF0C\u7B97\u662F\u5728\u670D\u52A1\u5668\u7F16\u7A0B\u65B9\u5411\u5165\u4E86\u95E8\u3002</p><p>\u603B\u7ED3\u4E0B\u6765\uFF0CC++\u7684\u96BE\u5EA6\u7EDD\u975E\u4EFB\u4F55\u4E00\u95E8\u8BED\u8A00\u53EF\u4EE5\u76F8\u63D0\u5E76\u8BBA\uFF0C\u6CA1\u6709\u57FA\u7840\u7684\u60C5\u51B5\u4E0B\u786C\u64B8\u662F\u884C\u4E0D\u901A\u7684\u3002\u53CD\u89C2\u70C2\u5927\u8857\u7684Java\u548Cweb\uFF0C\u95E8\u69DB\u4F4E\u96BE\u5EA6\u5C0F\uFF0C\u7F51\u8BFE\u89C6\u9891\u591A\uFF0C\u62C9\u6761\u72D7\u90FD\u80FD\u5B66\u4F1A\u3002\u5F53\u7136\u96BE\u5EA6\u518D\u4F4E\u7684\u9886\u57DF\uFF0C\u5B66\u7CBE\u4E86\u4E5F\u4F1A\u6709\u4E0D\u53EF\u4F01\u53CA\u7684\u5927\u5C71\u5B58\u5728\u3002\u4F46\u662F\u5F53\u4E0B\u800C\u8A00\uFF0C\u5B66Java\u7684\u5927\u5B66\u751F\u4EEC\u4F3C\u4E4E\u601D\u7EF4\u5DF2\u7ECF\u88AB\u7981\u9522\u5728\u4E86JVM\u91CC\uFF0C\u5E76\u4E14\u5929\u771F\u7684\u8BA4\u4E3A\u7F16\u7A0B\u5C31\u662F\u5199\u63A5\u53E3\uFF0C\u5BF9\u9664\u4E86\u524D\u540E\u7AEF\u5916\u7F16\u7A0B\u80FD\u505A\u7684\u4E8B\u60C5\u4E00\u65E0\u6240\u77E5\uFF0C\u751A\u81F3\u8FDE\u4E00\u4E2A\u6709\u5B9E\u9645\u529F\u80FD\u6027\u7684\u9879\u76EE\u90FD\u6CA1\u5199\u8FC7\uFF0C\u518D\u52A0\u4E0A\u5982\u4ECA\u524D\u540E\u7AEF\u7684\u5C31\u4E1A\u73AF\u5883\u5DEE\u81F3\u51B0\u70B9\uFF0C\u663E\u7136\u8FD9\u7C7B\u5927\u5B66\u751F\u5DF2\u7ECF\u65E0\u6CD5\u8D62\u5F97\u5C0A\u91CD\u3002</p><p>\u5B66\u4E60\u8FC7\u7A0B\u4E2D\u53D6\u5F97\u5B9E\u8D28\u6027\u5E2E\u52A9\u7684\u6587\u7AE0\uFF1A</p><p>https://blog.csdn.net/lepaitianshi/article/details/133035990</p><p>https://blog.csdn.net/m0_51551385/article/details/124359780</p><p>https://blog.csdn.net/XZbnhh/article/details/120689278</p><p>https://blog.csdn.net/qq_15054345/article/details/125368426</p><p>https://blog.csdn.net/weixin_60338047/article/details/130857596</p><h2 id="\u5B66\u4E60\u8DEF\u7EBF" tabindex="-1"><a class="header-anchor" href="#\u5B66\u4E60\u8DEF\u7EBF" aria-hidden="true">#</a> \u5B66\u4E60\u8DEF\u7EBF</h2><p>\u56E0\u4E3A\u6CA1\u4EBA\u5E26\uFF0C\u6211\u4E5F\u7B97\u662F\u8D70\u4E86\u5F88\u591A\u5F2F\u8DEF\uFF0C\u540E\u7EED\u81EA\u5DF1\u6574\u7406\u4E86\u4E0B\u6700\u5FEB\u7684\u5B66\u4E60\u8DEF\u5F84\uFF0C\u53EF\u4EE5\u53C2\u8003\u4E0B\uFF1A</p><p>\u9996\u5148\u5FC5\u987B\u4E0B\u529F\u592B\u5148\u719F\u8BFB\u300ATCP/IP\u7F51\u7EDC\u7F16\u7A0B\u300B\uFF0C\u7406\u89E3epoll\u7684\u7528\u6CD5\uFF0C\u540C\u65F6\u719F\u6089EPOLLONESHOT\u3001SO_REUSEADDR(WAIT_TIME)\u3001EPOLLONESHOT\u7B49\u7F51\u7EDC\u7F16\u7A0B\u5E38\u7528\u53C2\u6570\u3002</p><p>\u719F\u77E5\u8FB9\u7F18\u89E6\u53D1\u3001\u6761\u4EF6\u89E6\u53D1\u7684\u533A\u522B\u3002</p><p>\u5176\u6B21\u8981\u4F1A\u624B\u5199\u94FE\u8868\u3001\u591A\u7EBF\u7A0B\u3002</p><p>\u4E86\u89E3\u4FE1\u53F7\u3001\u5B9A\u65F6\u5668\u3001\u7BA1\u9053\u901A\u4FE1\u7B49\u673A\u5236\u3002</p><p>\u61C2\u4E00\u4E22\u4E22\u7684mysql\u3002</p><p>\u51E0\u4E4E\u6240\u6709\u5E94\u5C4AC++ Linux\u670D\u52A1\u5668\u7A0B\u5E8F\u5458\u9762\u8BD5\u91CC\uFF0C\u7B80\u5386\u91CC\u90FD\u4F1A\u5199WebServer\u9879\u76EE\uFF0CTinyWebServer\u8FD9\u4E2A\u9879\u76EE\u786E\u5B9E\u662F\u6781\u5176\u4F18\u79C0\u4E0E\u7CBE\u7B80\uFF0C\u6DB5\u76D6\u4E86Linux\u670D\u52A1\u5668\u7F16\u7A0B\u5E38\u7528\u7684\u6240\u6709\u5185\u5BB9\uFF0C\u6240\u4EE5\u662F\u5FC5\u5B66\u7684\u3002</p><p>\u6240\u4EE5\u6211\u4EEC\u638C\u63E1\u4EE5\u4E0A\u7684\u6280\u672F\u540E\uFF0C\u5C31\u8981\u5C1D\u8BD5\u8FD0\u884Ctinywebserver\u5E76\u5206\u6A21\u5757\u9605\u8BFB\uFF0C\u76F4\u81F3\u7406\u6E05\u6BCF\u4E00\u884C\u4EE3\u7801\u7684\u4F5C\u7528\uFF0C\u5E76\u80FD\u72EC\u7ACB\u4EFF\u5199\u51FA\u81EA\u5DF1\u7684webserver\u5C31\u7B97\u662F\u5927\u529F\u544A\u6210\u4E86\u3002\u8FD9\u4E2A\u8FC7\u7A0B\u53EF\u80FD\u4F1A\u6301\u7EED\u597D\u51E0\u5929\u751A\u81F3\u597D\u51E0\u5468\uFF0C\u4E0D\u8981\u5FC3\u6025\uFF0C\u671F\u95F4\u53EF\u4EE5\u5E26\u7740\u7FFB\u9605\u300ALinux\u9AD8\u6027\u80FD\u670D\u52A1\u5668\u7F16\u7A0B\u300B\uFF0C\u9047\u5230\u95EE\u9898\u6700\u597D\u6709\u4E2A\u5927\u4F6C\u6216\u8005\u524D\u8F88\u53EF\u4EE5\u8BF7\u6559\uFF0C\u90A3\u6837\u80FD\u5C11\u8D70\u5F88\u591A\u5F2F\u8DEF\u3002</p><h2 id="\u8FD0\u884Ctinywebserver" tabindex="-1"><a class="header-anchor" href="#\u8FD0\u884Ctinywebserver" aria-hidden="true">#</a> \u8FD0\u884CTinyWebServer</h2><p>\u8FD0\u884CTinyWebServer\u5927\u6982\u7387\u4F1A\u8E29\u5751\uFF0C\u5E76\u4E14\u53D1\u73B0\u7F51\u7EDC\u4E0A\u5E76\u6CA1\u6709\u4EFB\u4F55\u4E00\u7BC7\u6587\u7AE0\u662F\u5B8C\u6574\u89E3\u51B3\u95EE\u9898\u7684\uFF0C\u6211\u8BB0\u5F55\u4E86\u4E0B\u89E3\u51B3\u65B9\u6848\uFF1A</p><p>\u8FD9\u91CC\u4EE5Ubuntu\u4E3A\u4F8B\uFF0CTinyWebServer\u9700\u8981mysql\u73AF\u5883</p><blockquote><p>\u5B89\u88C5mysql</p></blockquote><p>sudo apt install mysql-server</p><blockquote><p>\u542F\u52A8mysql</p></blockquote><p>sudo service mysql start</p><blockquote><p>\u8BBE\u7F6Emysql\u7684root\u7528\u6237\u53CA\u5BC6\u7801</p></blockquote><p>sudo mysql -uroot -p</p><div class="language-mysql ext-mysql line-numbers-mode"><pre class="language-mysql"><code>use mysql;
ALTER USER &#39;root&#39;@&#39;localhost&#39; IDENTIFIED WITH mysql_native_password BY &#39;123456&#39;;
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p>\u8BBE\u7F6E\u8FDC\u7A0B\u8BBF\u95EEroot</p></blockquote><div class="language-mysql ext-mysql line-numbers-mode"><pre class="language-mysql"><code>UPDATE user SET \`Host\` = &#39;%&#39; WHERE \`User\` = &#39;root&#39; LIMIT 1;
flush privileges;
exit;
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>sudo vi /etc/mysql/mysql.conf.d/mysqld.cnf</p><p>\u5728bind-address = 127.0.0.1\u524D\u9762\u52A0#</p><blockquote><p>\u91CD\u542Fmysql</p></blockquote><p>service mysql restart</p><blockquote><p>\u6DFB\u52A0mysql\u5B89\u5168\u7EC4</p></blockquote><p>\u6B64\u65F6\u6211\u4EEC\u8981\u5C1D\u8BD5\u4F7F\u7528Navicat(\u968F\u4FBF)\u8FDE\u63A5\u6570\u636E\u5E93\uFF0C\u5982\u679C\u8FDE\u63A5\u4E0D\u4E0A\uFF0C\u5927\u6982\u7387\u662F\u9632\u706B\u5899\u51FA\u4E86\u95EE\u9898\uFF0C\u6211\u4EEC\u8981\u5F00\u653E3306\u7AEF\u53E3\u3002</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>\u6DFB\u52A0\u7AEF\u53E3\uFF1A firewall-cmd --zone<span class="token operator">=</span>public --add-port<span class="token operator">=</span><span class="token number">3306</span>/tcp --permanent
\u91CD\u542F\u9632\u706B\u5899\uFF1A firewall-cmd --reload\uFF1B
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>\u5982\u679C\u6CA1\u6709\u63D0\u793A\u6CA1\u6709firewall\uFF0C\u5219\u4F7F\u7528\u6307\u4EE4\u8FDB\u884C\u5B89\u88C5\u540E\u518D\u5C1D\u8BD5\u5173\u95ED\u9632\u706B\u5899</p><p>sudo apt install firewalld</p><blockquote><p>\u6DFB\u52A0\u6570\u636E\u5E93\u53CA\u8868\u6570\u636E</p></blockquote><p>\u968F\u540E\u6267\u884Csql\u547D\u4EE4</p><div class="language-mysql ext-mysql line-numbers-mode"><pre class="language-mysql"><code>create database yourdb;

USE yourdb;
CREATE TABLE user(
    username char(50) NULL,
    passwd char(50) NULL
)ENGINE=InnoDB;

INSERT INTO user(username, passwd) VALUES(&#39;name&#39;, &#39;passwd&#39;);
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>\u4FDD\u8BC1\u6570\u636E\u5E93\u80FD\u8FDE\u63A5\u4E0A\u7684\u60C5\u51B5\u4E0B\u518D\u8FDB\u884C\u4E0B\u4E00\u6B65\u64CD\u4F5C\uFF0C\u5426\u5219\u9879\u76EE\u5373\u4F7F\u8DD1\u8D77\u6765\u4E5F\u662F\u767D\u540A\u642D\u3002</p><blockquote><p>\u6DFB\u52A0server\u5B89\u5168\u7EC4</p></blockquote><p>\u9879\u76EE\u672C\u8EAB\u4E5F\u9700\u89819006\u7AEF\u53E3\uFF0C\u4E8E\u662F\u5F00\u653E\u4E00\u4E0B9006\u7AEF\u53E3</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>\u6DFB\u52A0\u7AEF\u53E3\uFF1A firewall-cmd --zone<span class="token operator">=</span>public --add-port<span class="token operator">=</span><span class="token number">9006</span>/tcp --permanent
\u91CD\u542F\u9632\u706B\u5899\uFF1A firewall-cmd --reload\uFF1B
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p>\u914D\u7F6Ecpp</p></blockquote><p>\u6253\u5F00main.cpp\u5E76\u4E14\u586B\u5165mysql\u53C2\u6570\u3002</p><p><img src="https://wqby-1304194722.cos.ap-nanjing.myqcloud.com/img/image-20231018184850380.png" alt="image-20231018184850380"></p><blockquote><p>\u5B89\u88C5\u4F9D\u8D56</p></blockquote><p>\u6B64\u65F6\u6211\u4EEC\u5C31\u914D\u7F6E\u597D\u4E86\u9700\u8981\u7684\u73AF\u5883\uFF0C\u968F\u540E\u6211\u4EEC\u5C1D\u8BD5make\u9879\u76EE\uFF0C\u53D1\u73B0\u627E\u4E0D\u5230&lt;mysql/mysql.h&gt;</p><p><img src="https://wqby-1304194722.cos.ap-nanjing.myqcloud.com/img/image-20231018180919458.png" alt="image-20231018180919458"></p><p>\u89E3\u51B3\u65B9\u6CD5:sudo apt-get install libmysqlclient-dev</p><blockquote><p>\u8FD0\u884C</p></blockquote><p>\u518D\u6B21make</p><p>\u8FD0\u884C./server</p><p>\u6B64\u65F6\u7528\u6D4F\u89C8\u5668\u6253\u5F00ip:9006\u5373\u53EF\u6B63\u5E38\u8BBF\u95EE\u4E86\u3002</p><p>\u671F\u95F4\u5982\u679C\u914D\u7F6E\u51FA\u9519\uFF0C\u81EA\u5DF1\u90FD\u641E\u6655\u4E86\u7684\u8BDD\uFF0C\u90A3\u5C31\u5F7B\u5E95\u5378\u8F7Dmysql\u518D\u91CD\u65B0\u64CD\u4F5C\u3002</p><ol><li><p>\u505C\u6B62Mysql\u670D\u52A1</p><p>sudo systemctl stop mysql</p></li><li><p>\u5378\u8F7DMysql\u670D\u52A1\u5668</p><p>sudo apt remove --purge mysql-server</p></li><li><p>\u5378\u8F7DMysql\u5171\u4EAB\u5E93</p><p>sudo apt remove --purge mysql-common</p></li><li><p>\u5220\u9664MYSQL\u914D\u7F6E\u6587\u4EF6\u548C\u6570\u636E\u76EE\u5F55</p><p>sudo rm -rf /etc/mysql /var/lib/mysql</p></li></ol><h2 id="\u4E0B\u4E00\u6B65\u5B66\u4E60\u8BA1\u5212" tabindex="-1"><a class="header-anchor" href="#\u4E0B\u4E00\u6B65\u5B66\u4E60\u8BA1\u5212" aria-hidden="true">#</a> \u4E0B\u4E00\u6B65\u5B66\u4E60\u8BA1\u5212</h2><p>\u6211\u5C06\u6DF1\u5165\u5B66\u4E60\u5B89\u5353\u624B\u6E38\u9006\u5411\uFF0C\u5C06\u5DF2\u5B66\u7684\u5B89\u5353Java\u5C42\u3001so\u5C42\u9006\u5411\u6280\u672F\u3001C++\u3001Linux\u7F16\u7A0B\u8FDB\u884C\u7ED3\u5408\uFF0C\u5728\u7F16\u7A0B\u4E2D\u9006\u5411\uFF0C\u5728\u9006\u5411\u4E2D\u63D0\u5347\u7F16\u7A0B\u3002</p><h2 id="\u611F\u60F3" tabindex="-1"><a class="header-anchor" href="#\u611F\u60F3" aria-hidden="true">#</a> \u611F\u60F3</h2><p>\u5728\u4E2D\u56FD\u8FD9\u6837\u5168\u4E16\u754C\u6700\u5DEE\u7684\u5C31\u4E1A\u5927\u73AF\u5883\u4E0B\uFF0C\u628A\u7F16\u7A0B\u5F53\u6210\u4E00\u95E8\u6280\u672F\u800C\u975E\u5B66\u79D1\uFF0C\u5C06\u6280\u672F\u8F6C\u6362\u6210\u4E00\u79CD\u4E0D\u7528\u4E0A\u73ED\u4E5F\u80FD\u76C8\u5229\u7684\u624B\u6BB5\uFF0C\u4E5F\u8BB8\u624D\u662F\u7A0B\u5E8F\u5458\u6700\u597D\u7684\u51FA\u8DEF\u3002</p>`,65);function p(l,r){return n}var t=e(a,[["render",p],["__file","2023-10-18 TinyWebServer\u624B\u64B8\u8BB0\u5F55.html.vue"]]);export{t as default};
